class MaxStack:
    def __init__(self):
        self.st = []; self.mx = []
    def push(self, x):
        self.st.append(x)
        self.mx.append(max(x, self.mx[-1] if self.mx else x))
    def pop(self): self.mx.pop(); return self.st.pop()
    def top(self): return self.st[-1]
    def peekMax(self): return self.mx[-1]
    def popMax(self):
        m = self.mx[-1]; tmp = []
        while self.st[-1] != m: tmp.append(self.pop())
        self.pop()
        while tmp: self.push(tmp.pop())
        return m

